// // This module implements a 16-bit down/up counter with enable and reset signals. The counter should count down when the mode is high and count up when the mode is low. The counter should be reset to zero when the reset signal is high.
module up_down_counter(
    input                 clk,
    input                 rst,
    input                 en,
    input                 mode,
    output  reg [15:0]    count
);

// Counter logic
always @(posedge clk or posedge rst) begin
    if (rst) begin
        count <= 16'd0;
    end else if (en) begin
        if (mode) begin
            count <= count + 1;
        end else begin
            count <= count - 1;
        end
    end
end

endmodule
